// lib/api/events.ts

import { EventCategory } from '@/types';

interface FetchEventsParams {
  token?: string;
  currentPage?: number;
  eventsPerPage?: number;
  activeFilter?:
    | 'all'
    | 'upcoming'
    | 'past'
    | 'price'
    | 'pending'
    | 'approved'
    | 'rejected';
  role?: 'admin' | 'host' | 'user' | 'public';
  toast?: any;
  setLoading?: (val: boolean) => void;
}

/**
 * Fetch events based on user role
 */
export const fetchEvents = async ({
  token,
  currentPage = 1,
  eventsPerPage = 3,
  activeFilter = 'all',
  role = 'public',
  toast,
  setLoading,
}: FetchEventsParams) => {
  if (setLoading) setLoading(true);

  const filterType =
    activeFilter === 'all'
      ? ''
      : activeFilter === 'upcoming'
      ? 'upcoming'
      : activeFilter === 'past'
      ? 'past'
      : '';

  // تحديد الـ endpoint حسب الدور
  let endpoint = '';
  switch (role) {
    case 'admin':
      endpoint = `http://localhost:8080/admin/events`;
      break;
    case 'host':
      endpoint = `http://localhost:8080/host/events`;
      break;
    case 'user':
    case 'public':
    default:
      endpoint = `http://localhost:8080/events`;
      break;
  }

  try {
    const res = await fetch(
      `${endpoint}?page=${currentPage}&perPage=${eventsPerPage}&type=${filterType}`,
      {
        method: 'GET',
        headers: {
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
          'Content-Type': 'application/json',
        },
      }
    );

    const data = await res.json();

    if (!res.ok) throw new Error(data.message || 'Failed to fetch events.');

    // معالجة إضافية لو المستخدم (لتحديث حالة التسجيل من localStorage)
    const updatedEvents = data.events?.map((event: EventCategory) => ({
      ...event,
      isRegistered:
        typeof window !== 'undefined' &&
        localStorage.getItem(`registered_${event._id}`) === 'true',
    }));

    return {
      events: updatedEvents || data.events || [],
      totalItems: data.totalItems || 0,
      totalPages:
        data.totalPages || Math.ceil((data.totalItems || 0) / eventsPerPage),
    };
  } catch (error: unknown) {
    if (error instanceof Error) {
      toast({
        title: 'Error',
        description: error.message,
        variant: 'destructive',
      });
    } else {
      toast({
        title: 'Error',
        description: 'An unexpected error occurred.',
        variant: 'destructive',
      });
    }
    return { events: [], totalItems: 0, totalPages: 0 };
  } finally {
    if (setLoading) setLoading(false);
  }
};
