import { StatItem } from '@/constants/stats';
import { motion } from 'framer-motion';

export const StatCard = ({
  title,
  value,
  change,
  icon,
  delay = 0,
}: StatItem) => {
  const Icon = icon; // ← تحويل الأيقونة إلى مكون قابل للعرض

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay }}
      className="bg-white p-6 rounded-xl shadow-md border border-gray-100 hover:shadow-lg transition-all"
    >
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm text-gray-500">{title}</p>
          <p className="text-2xl font-bold mt-2">{value}</p>
          <span
            className={`text-sm ${
              change.startsWith('+') ? 'text-green-600' : 'text-red-600'
            }`}
          >
            {change}
          </span>
        </div>
        <div className="p-3 bg-indigo-100 rounded-full">
          <Icon className="w-6 h-6 text-indigo-600" /> {/* ← عرض الأيقونة */}
        </div>
      </div>
    </motion.div>
  );
};